import React, { useEffect, useState, useCallback } from "react";
import { getBorrows, borrowBook, returnBook, getBooks, getMembers } from "../api";
import Modal from "../components/Modal";
import "./Page.css";

const today = new Date();
const defaultDue = new Date(today.getTime() + 14 * 86400000).toISOString().split("T")[0];

const Borrows = () => {
  const [borrows, setBorrows]   = useState([]);
  const [books, setBooks]       = useState([]);
  const [members, setMembers]   = useState([]);
  const [loading, setLoading]   = useState(true);
  const [filter, setFilter]     = useState("");
  const [showModal, setShowModal] = useState(false);
  const [form, setForm]         = useState({ book_id: "", member_id: "", due_date: defaultDue });
  const [submitting, setSubmitting] = useState(false);
  const [error, setError]       = useState("");

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const res = await getBorrows(filter ? { status: filter } : {});
      setBorrows(res.data.data);
    } catch { setError("Failed to load borrows."); }
    finally { setLoading(false); }
  }, [filter]);

  useEffect(() => { load(); }, [load]);

  const openModal = async () => {
    setError(""); setForm({ book_id: "", member_id: "", due_date: defaultDue });
    try {
      const [b, m] = await Promise.all([getBooks(), getMembers()]);
      setBooks(b.data.data.filter(bk => bk.available_copies > 0));
      setMembers(m.data.data.filter(mb => mb.is_active));
    } catch { setError("Could not load books/members."); }
    setShowModal(true);
  };

  const handleBorrow = async (e) => {
    e.preventDefault();
    setSubmitting(true); setError("");
    try {
      await borrowBook(form);
      setShowModal(false); load();
    } catch (err) {
      setError(err.response?.data?.error || "Could not issue book.");
    } finally { setSubmitting(false); }
  };

  const handleReturn = async (id) => {
    if (!window.confirm("Mark this book as returned?")) return;
    try { await returnBook(id); load(); }
    catch (err) { setError(err.response?.data?.error || "Return failed."); }
  };

  const isOverdue = (row) => row.status === "borrowed" && new Date(row.due_date) < new Date();

  return (
    <div>
      <div className="page-header">
        <div>
          <h1 className="page-title">Borrows</h1>
          <p className="page-sub">{borrows.length} records</p>
        </div>
        <button className="btn btn--primary" onClick={openModal}>+ Issue Book</button>
      </div>

      {error && <div className="alert alert--error">{error} <button onClick={() => setError("")}>✕</button></div>}

      <div className="toolbar">
        {["", "borrowed", "returned", "overdue"].map((s) => (
          <button key={s} className={`filter-btn ${filter === s ? "filter-btn--active" : ""}`}
            onClick={() => setFilter(s)}>
            {s === "" ? "All" : s.charAt(0).toUpperCase() + s.slice(1)}
          </button>
        ))}
      </div>

      {loading ? <div className="loading">Loading...</div> : (
        <div className="table-wrap">
          <table className="table">
            <thead>
              <tr>
                <th>#</th><th>Book</th><th>Member</th><th>Borrowed</th>
                <th>Due Date</th><th>Returned</th><th>Status</th><th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {borrows.length === 0 ? (
                <tr><td colSpan={8} className="empty-row">No records found.</td></tr>
              ) : borrows.map((r, i) => (
                <tr key={r.id} className={isOverdue(r) ? "row--overdue" : ""}>
                  <td className="muted">{i + 1}</td>
                  <td><strong>{r.book_title}</strong><br /><span className="muted small">{r.isbn}</span></td>
                  <td>{r.member_name}<br /><span className="muted small">{r.member_email}</span></td>
                  <td className="muted">{new Date(r.borrowed_at).toLocaleDateString("en-IN")}</td>
                  <td className={isOverdue(r) ? "text-danger" : ""}>
                    {new Date(r.due_date).toLocaleDateString("en-IN")}
                  </td>
                  <td className="muted">{r.returned_at ? new Date(r.returned_at).toLocaleDateString("en-IN") : "—"}</td>
                  <td>
                    <span className={`badge ${
                      r.status === "returned" ? "badge--green" :
                      isOverdue(r) ? "badge--red" : "badge--blue"
                    }`}>
                      {isOverdue(r) && r.status === "borrowed" ? "Overdue" : r.status}
                    </span>
                  </td>
                  <td>
                    {r.status === "borrowed" && (
                      <button className="btn btn--sm btn--primary" onClick={() => handleReturn(r.id)}>
                        Return
                      </button>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {showModal && (
        <Modal title="Issue a Book" onClose={() => setShowModal(false)}>
          <form onSubmit={handleBorrow} className="modal-form">
            {error && <div className="alert alert--error">{error}</div>}
            <div className="form-group">
              <label>Select Book (available only) *</label>
              <select required value={form.book_id} onChange={e => setForm({...form, book_id: e.target.value})}>
                <option value="">-- Select Book --</option>
                {books.map(b => (
                  <option key={b.id} value={b.id}>{b.title} — {b.author} ({b.available_copies} left)</option>
                ))}
              </select>
            </div>
            <div className="form-group">
              <label>Select Member *</label>
              <select required value={form.member_id} onChange={e => setForm({...form, member_id: e.target.value})}>
                <option value="">-- Select Member --</option>
                {members.map(m => (
                  <option key={m.id} value={m.id}>{m.name} ({m.email})</option>
                ))}
              </select>
            </div>
            <div className="form-group">
              <label>Due Date *</label>
              <input required type="date" value={form.due_date} min={new Date().toISOString().split("T")[0]}
                onChange={e => setForm({...form, due_date: e.target.value})} />
            </div>
            <div className="modal-actions">
              <button type="button" className="btn btn--outline" onClick={() => setShowModal(false)}>Cancel</button>
              <button type="submit" className="btn btn--primary" disabled={submitting}>
                {submitting ? "Issuing..." : "Issue Book"}
              </button>
            </div>
          </form>
        </Modal>
      )}
    </div>
  );
};

export default Borrows;
